export function setDeepValue(obj, [prop, ...path], value) {
  if (!path.length) {
    obj[prop] = value;
  } else {
    if (!(prop in obj)) obj[prop] = {};
    setDeepValue(obj[prop], path, value);
  }
}
export function getDeepValue(obj, [prop, ...path]) {
  if (!path.length) {
    return obj[prop];
  } else {
    if (!(prop in obj)) return undefined;
    return getDeepValue(obj[prop], path);
  }
}